2022.02.19 四题 day8 Codeforces Round #723 (Div. 2) A-C2 A 思路 对bi排序 按 b1 b2n b2 b2n-1 … 这样每个都要比两边的大 或比两边都小 Code 123456789101112131415161718192021int main()&#123; int t;io;cin&gt;&gt;t; while(t--)&#123; int n; cin&gt;&gt;n; n&lt;&lt;=1; vector&lt;int&gt; a(n); for(int i=0;i&lt;n;i++)&#123; cin&gt;&gt;a[i]; &#125; sort(all(a)); vector&lt;int&gt; b(n); for(int i=0;i&lt;n/2;i++)&#123; b[2*i]=a[i]; b[2*i+1]=a[n-1-i]; &#125; for(int i=0;i&lt;n;i++) cout&lt;&lt;b[i]&lt;&lt;&quot; &quot;;cn; &#125; return 0;&#125; B 思路 1111以上的都可以用11和111组合而成，所以用11 111即可 Code 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103#include&lt;bits/stdc++.h&gt;using namespace std;#define rep(i, a, b) for(int i = a; i &lt;= b; i++)#define _rep(i, a, b) for(int i = a; i &gt;= b; i --)#define nrep(i,a,b) for(i=a;i&lt;=b;i++)#define io std::ios::sync_with_stdio(false),cin.tie(0),cout.tie(0)#define pb push_back#define mp make_pair#define fi first#define se second#define ll long long#define ull unsigned long long#define pii pair&lt;int,int&gt; #define pll pair&lt;ll,ll&gt; #define puu pair&lt;ull,ull&gt; #define mem(x) memset(x,0,sizeof(x))#define memax(x) memset(x,INF,sizeof(x))#define _mem(x) memset(x,-1,sizeof(x))#define max3(x,y,z) max(max(x,y),z)#define INF 0x3f3f3f3f#define eps 1e-8#define sdd(x,y) scanf(&quot;%d%d&quot;,&amp;x,&amp;y)#define sddd(x,y,z) scanf(&quot;%d%d%d&quot;,&amp;x,&amp;y,&amp;z)#define sd(x) scanf(&quot;%d&quot;,&amp;x)#define pd(x) printf(&quot;%d&quot;,x)#define pdn(x) printf(&quot;%d
