&quot;)//#define all(x) x.begin(),x.end()#define cn cout&lt;&lt;endl#define all(s0) s0.begin(),s0.end()#define ins(s0) inserter(s0,s0.begin())namespace acm&#123; typedef long long ET; inline ET read()&#123; ET ans=0;char r=getchar(); while(r&lt;&#x27;0&#x27;||r&gt;&#x27;9&#x27;)r=getchar(); while(r&gt;=&#x27;0&#x27;&amp;&amp;r&lt;=&#x27;9&#x27;)&#123;ans=ans*10+r-&#x27;0&#x27;;r=getchar();&#125; return ans; &#125; ET qpow(ET a,ET b,ET p)&#123;//a^b%p ET res=1%p; while(b)&#123; if(b&amp;1)res=(long long)res*a%p; a=(long long)a*a%p; b&gt;&gt;=1; &#125; return res; &#125; long long mul(long long a,long long b,long long p)&#123;//a*b%p long long ans=0; while(b)&#123; if(b&amp;1)ans=(ans+a)%p; a=(a&lt;&lt;1)%p; b&gt;&gt;=1; &#125; return ans; &#125; int lowbit(int n)&#123; return n&amp;(-n); &#125;&#125;using namespace acm;/*//增序列中选&gt;=x最小解while(l&lt;r)&#123; int mid=(l+r)&gt;&gt;1; if(a[mid]&gt;=x)r=mid; else l=mid+1;&#125;return a[l];//增序列中选&lt;=x最大解while(l&lt;r)&#123; int mid=(l+r+1)&gt;&gt;1; if(a[mid]&lt;=x)l=mid; else r=mid-1;&#125;return a[l];*/int n;bool solve()&#123; if(n%111==0)return 1; while(1)&#123; if(n&lt;0)return 0; if(n%11==0)return 1; n-=111; &#125;&#125;int main()&#123; int t;io;cin&gt;&gt;t; while(t--)&#123; cin&gt;&gt;n; cout&lt;&lt;(solve()?&quot;YES
&quot;:&quot;NO
&quot;); &#125; return 0;&#125; C1&amp;C2 我的算法两个都能过 思路 正数必然要选，负数如果符合条件就也加入，如果不符合条件看看是否能够替换某一个过小的负数使选取保持最优，通过维护一个最大堆实现。 Code 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113#include&lt;bits/stdc++.h&gt;using namespace std;#define rep(i, a, b) for(int i = a; i &lt;= b; i++)#define _rep(i, a, b) for(int i = a; i &gt;= b; i --)#define nrep(i,a,b) for(i=a;i&lt;=b;i++)#define io std::ios::sync_with_stdio(false),cin.tie(0),cout.tie(0)#define pb push_back#define mp make_pair#define fi first#define se second#define ll long long#define ull unsigned long long#define pii pair&lt;int,int&gt; #define pll pair&lt;ll,ll&gt; #define puu pair&lt;ull,ull&gt; #define mem(x) memset(x,0,sizeof(x))#define memax(x) memset(x,INF,sizeof(x))#define _mem(x) memset(x,-1,sizeof(x))#define max3(x,y,z) max(max(x,y),z)#define INF 0x3f3f3f3f#define eps 1e-8//#define all(x) x.begin(),x.end()#define cn cout&lt;&lt;endl#define all(s0) s0.begin(),s0.end()#define ins(s0) inserter(s0,s0.begin())#define pn cout&lt;&lt;&quot;NO&quot;&lt;&lt;endl#define py cout&lt;&lt;&quot;YES&quot;&lt;&lt;endlnamespace acm&#123; typedef long long ET; inline ET read()&#123; ET ans=0;char r=getchar(); while(r&lt;&#x27;0&#x27;||r&gt;&#x27;9&#x27;)r=getchar(); while(r&gt;=&#x27;0&#x27;&amp;&amp;r&lt;=&#x27;9&#x27;)&#123;ans=ans*10+r-&#x27;0&#x27;;r=getchar();&#125; return ans; &#125; ET qpow(ET a,ET b,ET p)&#123;//a^b%p ET res=1%p; while(b)&#123; if(b&amp;1)res=(long long)res*a%p; a=(long long)a*a%p; b&gt;&gt;=1; &#125; return res; &#125; long long mul(long long a,long long b,long long p)&#123;//a*b%p long long ans=0; while(b)&#123; if(b&amp;1)ans=(ans+a)%p; a=(a&lt;&lt;1)%p; b&gt;&gt;=1; &#125; return ans; &#125; int lowbit(int n)&#123; return n&amp;(-n); &#125;&#125;using namespace acm;/*//增序列中选&gt;=x最小解while(l&lt;r)&#123; int mid=(l+r)&gt;&gt;1; if(a[mid]&gt;=x)r=mid; else l=mid+1;&#125;return a[l];//增序列中选&lt;=x最大解while(l&lt;r)&#123; int mid=(l+r+1)&gt;&gt;1; if(a[mid]&lt;=x)l=mid; else r=mid-1;&#125;return a[l];*/int const N = 2e3+10;int a[N];priority_queue&lt;int&gt; q;int main()&#123; int n;io; cin&gt;&gt;n; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; long long sum=0; int ans=0; for(int i=1;i&lt;=n;i++)&#123; if(a[i]&gt;=0)&#123; sum+=a[i]; ans++; &#125; else&#123; if(sum+a[i]&gt;=0)&#123; sum+=a[i]; q.push(-a[i]); ans++; &#125; else if(q.size()&amp;&amp;q.top()&gt;=-a[i])&#123; sum+=q.top(); sum+=a[i]; q.pop(); q.push(-a[i]); &#125; &#125; &#125; cout&lt;&lt;ans; return 0;&#125;

2022.02.17 四题 day7Codeforces Round #727 (Div. 2)A-D A 思路 分成每个的贡献分别是 d/x d/x … d/x d/x-1 … 0 Code 12345678910111213int main()&#123; ll t=read(); while(t--)&#123; ll n,x,t; cin&gt;&gt;n&gt;&gt;x&gt;&gt;t; ll cnt=t/x; ll sum; if(cnt+1&lt;=n)sum=cnt*(cnt+1)/2+cnt*(n-cnt-1); else sum=(n-1+0)*n/2; cout&lt;&lt;sum&lt;&lt;endl; &#125; return 0;&#125; B 思路 简单前缀和处理一下 Code 12345678910111213141516171819202122 int const N =1e5+6;long long a[N];long long sum[N];int main()&#123; int n,q; cin&gt;&gt;n&gt;&gt;q; string s; cin&gt;&gt;s; a[0]=s[0]-&#x27;a&#x27;+1; sum[0]=a[0]; for(int i=1;i&lt;n;i++)&#123; a[i]=s[i]-&#x27;a&#x27;+1; sum[i]=sum[i-1]+a[i]; &#125; while(q--)&#123; int l,r; cin&gt;&gt;l&gt;&gt;r; cout&lt;&lt;(sum[r-1]-sum[l-1]+a[l-1])&lt;&lt;endl; &#125; return 0;&#125; C 思路 把差值放入数组中排序，贪心的去取 Code 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111#include&lt;bits/stdc++.h&gt;using namespace std;#define rep(i, a, b) for(int i = a; i &lt;= b; i++)#define _rep(i, a, b) for(int i = a; i &gt;= b; i --)#define nrep(i,a,b) for(i=a;i&lt;=b;i++)#define io std::ios::sync_with_stdio(false),cin.tie(0),cout.tie(0)#define pb push_back#define mp make_pair#define fi first#define se second#define ll long long#define ull unsigned long long#define pii pair&lt;int,int&gt; #define pll pair&lt;ll,ll&gt; #define puu pair&lt;ull,ull&gt; #define mem(x) memset(x,0,sizeof(x))#define memax(x) memset(x,INF,sizeof(x))#define _mem(x) memset(x,-1,sizeof(x))#define max3(x,y,z) max(max(x,y),z)#define INF 0x3f3f3f3f#define eps 1e-8#define sdd(x,y) scanf(&quot;%d%d&quot;,&amp;x,&amp;y)#define sddd(x,y,z) scanf(&quot;%d%d%d&quot;,&amp;x,&amp;y,&amp;z)#define sd(x) scanf(&quot;%d&quot;,&amp;x)#define pd(x) printf(&quot;%d&quot;,x)#define pdn(x) printf(&quot;%d
&quot;,x)#define pn printf(&quot;
&quot;)//#define all(x) x.begin(),x.end()#define cn cout&lt;&lt;endl#define all(s0) s0.begin(),s0.end()#define ins(s0) inserter(s0,s0.begin())namespace acm&#123; typedef long long ET; inline ET read()&#123; ET ans=0;char r=getchar(); while(r&lt;&#x27;0&#x27;||r&gt;&#x27;9&#x27;)r=getchar(); while(r&gt;=&#x27;0&#x27;&amp;&amp;r&lt;=&#x27;9&#x27;)&#123;ans=ans*10+r-&#x27;0&#x27;;r=getchar();&#125; return ans; &#125; ET qpow(ET a,ET b,ET p)&#123;//a^b%p ET res=1%p; while(b)&#123; if(b&amp;1)res=(long long)res*a%p; a=(long long)a*a%p; b&gt;&gt;=1; &#125; return res; &#125; long long mul(long long a,long long b,long long p)&#123;//a*b%p long long ans=0; while(b)&#123; if(b&amp;1)ans=(ans+a)%p; a=(a&lt;&lt;1)%p; b&gt;&gt;=1; &#125; return ans; &#125; int lowbit(int n)&#123; return n&amp;(-n); &#125;&#125;using namespace acm;/*//增序列中选&gt;=x最小解while(l&lt;r)&#123; int mid=(l+r)&gt;&gt;1; if(a[mid]&gt;=x)r=mid; else l=mid+1;&#125;return a[l];//增序列中选&lt;=x最大解while(l&lt;r)&#123; int mid=(l+r+1)&gt;&gt;1; if(a[mid]&lt;=x)l=mid; else r=mid-1;&#125;return a[l];*/int const N = 2e5+10;long long n,k,x;long long a[N];void solve()&#123; for(int i=1;i&lt;=n;i++) cin&gt;&gt;a[i]; sort(a+1,a+1+n); vector&lt;ll&gt; b; for(int i=2;i&lt;=n;i++)&#123; b.pb(max(0LL,a[i]-a[i-1]-1)/x); &#125; sort(all(b)); long long sum=n; for(int i=0;i&lt;b.size();i++)&#123; if(k&gt;=b[i])&#123; k-=b[i]; sum--; &#125; &#125; cout&lt;&lt;sum&lt;&lt;endl;&#125;int main()&#123; cin&gt;&gt;n&gt;&gt;k&gt;&gt;x; solve(); return 0;&#125; D 思路 首先题目里有一个陷阱：可以通过刷不必要的单让别的单获得折扣价。 如果多刷了一单 多花了1，然后去购买一个1 和直接买没有区别 按bi从小到大排列，两点解决问题。 因为右边的必然比左边的难到达折扣价，每次操作都先从右边买。（除非达到折扣） 如果当前已经达到折扣，从左边开始一直买 如果买当前bi大的一部分可以达到折扣，从右边购买 不然买空右边 Code 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123124#include&lt;bits/stdc++.h&gt;using namespace std;#define rep(i, a, b) for(int i = a; i &lt;= b; i++)#define _rep(i, a, b) for(int i = a; i &gt;= b; i --)#define nrep(i,a,b) for(i=a;i&lt;=b;i++)#define io std::ios::sync_with_stdio(false),cin.tie(0),cout.tie(0)#define pb push_back#define mp make_pair#define fi first#define se second#define ll long long#define ull unsigned long long#define pii pair&lt;int,int&gt; #define pll pair&lt;ll,ll&gt; #define puu pair&lt;ull,ull&gt; #define mem(x) memset(x,0,sizeof(x))#define memax(x) memset(x,INF,sizeof(x))#define _mem(x) memset(x,-1,sizeof(x))#define max3(x,y,z) max(max(x,y),z)#define INF 0x3f3f3f3f#define eps 1e-8#define sdd(x,y) scanf(&quot;%d%d&quot;,&amp;x,&amp;y)#define sddd(x,y,z) scanf(&quot;%d%d%d&quot;,&amp;x,&amp;y,&amp;z)#define sd(x) scanf(&quot;%d&quot;,&amp;x)#define pd(x) printf(&quot;%d&quot;,x)#define pdn(x) printf(&quot;%d
&quot;,x)#define pn printf(&quot;
&quot;)//#define all(x) x.begin(),x.end()#define cn cout&lt;&lt;endl#define all(s0) s0.begin(),s0.end()#define ins(s0) inserter(s0,s0.begin())namespace acm&#123; typedef long long ET; inline ET read()&#123; ET ans=0;char r=getchar(); while(r&lt;&#x27;0&#x27;||r&gt;&#x27;9&#x27;)r=getchar(); while(r&gt;=&#x27;0&#x27;&amp;&amp;r&lt;=&#x27;9&#x27;)&#123;ans=ans*10+r-&#x27;0&#x27;;r=getchar();&#125; return ans; &#125; ET qpow(ET a,ET b,ET p)&#123;//a^b%p ET res=1%p; while(b)&#123; if(b&amp;1)res=(long long)res*a%p; a=(long long)a*a%p; b&gt;&gt;=1; &#125; return res; &#125; long long mul(long long a,long long b,long long p)&#123;//a*b%p long long ans=0; while(b)&#123; if(b&amp;1)ans=(ans+a)%p; a=(a&lt;&lt;1)%p; b&gt;&gt;=1; &#125; return ans; &#125; int lowbit(int n)&#123; return n&amp;(-n); &#125;&#125;using namespace acm;/*//增序列中选&gt;=x最小解while(l&lt;r)&#123; int mid=(l+r)&gt;&gt;1; if(a[mid]&gt;=x)r=mid; else l=mid+1;&#125;return a[l];//增序列中选&lt;=x最大解while(l&lt;r)&#123; int mid=(l+r+1)&gt;&gt;1; if(a[mid]&lt;=x)l=mid; else r=mid-1;&#125;return a[l];*/int const N = 1e5+10;struct Node&#123; ll a,b;&#125;;bool cmp(Node x,Node y)&#123; return x.b&lt;y.b;&#125;Node s[N];int main()&#123; int n;io; cin&gt;&gt;n; for(int i=1;i&lt;=n;i++)&#123; cin&gt;&gt;s[i].a&gt;&gt;s[i].b; &#125; sort(s+1,s+1+n,cmp); int l=1,r=n; ll ans=0,sum=0; while(l&lt;=r)&#123; if(sum&gt;=s[l].b)&#123; ans+=s[l].a; sum+=s[l].a; l++; &#125; else if(sum+s[r].a&gt;=s[l].b)&#123; s[r].a-=(s[l].b-sum); ans+=2*(s[l].b-sum); sum=s[l].b; &#125; else&#123; sum+=s[r].a; ans+=2*s[r].a; r--; &#125; &#125; cout&lt;&lt;ans&lt;&lt;endl; return 0;&#125;

2022.02.13 四题 day6Codeforces Round #754 (Div. 2)A-D A 思路 每次可以选择任意两个分别加减，也就是说我们可以任意重新分配 设 d= a+b+c 根据d%3分类讨论 Code 1234567891011121314int main()&#123; io; int t; cin&gt;&gt;t; while(t--)&#123; int a,b,c; cin&gt;&gt;a&gt;&gt;b&gt;&gt;c; int d=a+b+c; if(d%3==0)cout&lt;&lt;0; else cout&lt;&lt;1; cn; &#125; return 0;&#125; B 思路 看了题解感觉自己是个笨比 排序后就是 0…0 1…1 那么把位置不对的选出来交换不就好了吗 Code 12345678910111213141516171819202122232425262728293031323334353637int const N = 1e3+10; int main()&#123; io; int t; cin&gt;&gt;t; while(t--)&#123; int n;string s; cin&gt;&gt;n&gt;&gt;s; int cnt0=0; for(int i=0;i&lt;n;i++)&#123; if(s[i]==&#x27;0&#x27;)cnt0++; &#125; //int cnt1=n-cnt0; vector&lt;int&gt; ans; for(int i=0;i&lt;cnt0;i++)&#123; if(s[i]!=&#x27;0&#x27;)&#123; ans.pb(i+1); &#125; &#125; for(int i=cnt0;i&lt;n;i++)&#123; if(s[i]==&#x27;0&#x27;)&#123; ans.pb(i+1); &#125; &#125; if(ans.size()==0)&#123; cout&lt;&lt;0&lt;&lt;endl; continue; &#125; cout&lt;&lt;1&lt;&lt;endl&lt;&lt;ans.size()&lt;&lt;&quot; &quot;; for(auto it:ans)&#123; cout&lt;&lt;it&lt;&lt;&quot; &quot;; &#125; cn; &#125; return 0;&#125; C 思路 一开始想到找 aba aca aa类，wa 然后想到abca acba也是可以的 wa 最后又又又发现，原来abbacca accabba 也是可以的. 😵 Code 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106#include&lt;bits/stdc++.h&gt;using namespace std;#define rep(i, a, b) for(int i = a; i &lt;= b; i++)#define _rep(i, a, b) for(int i = a; i &gt;= b; i --)#define nrep(i,a,b) for(i=a;i&lt;=b;i++)#define io std::ios::sync_with_stdio(false),cin.tie(0),cout.tie(0)#define pb push_back#define mp make_pair#define fi first#define se second#define ll long long#define ull unsigned long long#define pii pair&lt;int,int&gt; #define pll pair&lt;ll,ll&gt; #define puu pair&lt;ull,ull&gt; #define mem(x) memset(x,0,sizeof(x))#define memax(x) memset(x,INF,sizeof(x))#define _mem(x) memset(x,-1,sizeof(x))#define max3(x,y,z) m