&quot;,score); &#125; return 0;&#125; 分解 其实本来他只是一道简单的对n求质因数的题，但是我感觉这样可能太直白，太水了，所以加了一个阶乘 让我们想一个结论，如果n!中的i，他的质因子，同时也是n!的质因子 好像有一个整数唯一分解定理，有兴趣可以去查一下 如果你想先求出n!的话会惊喜的发现太大了那么我们可以遍历1到n，求出他们的质因子，分别保存，然后再在最后输出 123456789101112131415161718192021222324252627//#include&lt;iostream&gt;//using namespace std;#include&lt;cstdio&gt;#include&lt;cstring&gt;int a[10001]; int main()&#123; int n; memset(a,0,sizeof a); scanf(&quot;%d&quot;,&amp;n); for (int i=2;i&lt;=n;i++) &#123; int k=i; for (int j=2;j&lt;=i;j++) while (k%j==0) &#123; a[j]++; k/=j; &#125; &#125; for (int i=10000;i&gt;=1;i--) if (a[i]!=0) &#123; printf(&quot;%d %d
&quot;,i,a[i]); &#125; return 0;&#125; 玩蛇 这道题还是找规律吧，或者说这类的题都是找规律的可以发现，从点（0，0）开始，顺时针绕圈。我们可以模拟一下，把x,y初始化(0,0)，然后移动，如果走出范围或者要移动到的位置已经走过（代表现在走到了更内圈），就换下一个方向 顺便一提，这种题目有两种方法，一种是把图像保存在数组里，之后再输出，一种是一边循环一边输出，看题目要求选择。 1234567891011121314151617181920212223242526272829#include&lt;stdio.h&gt;#include&lt;cstring&gt;using namespace std;const int maxn = 20;int a[maxn][maxn];int main()&#123; int n; scanf(&quot;%d&quot;,&amp;n); int tot=1, x, y; memset(a, 0, sizeof(a)); a[x][y]=1; while (tot&lt;n*n) &#123; while (y + 1&lt;n&amp;&amp;!a[x][y + 1])a[x][++y] = ++tot; while (x + 1&lt;n&amp;&amp;!a[x + 1][y])a[++x][y] = ++tot; while (y - 1 &gt;= 0 &amp;&amp; !a[x][y - 1])a[x][--y] = ++tot; while (x - 1 &gt;= 0 &amp;&amp; !a[x - 1][y])a[--x][y] = ++tot; &#125; for (int i = 0; i&lt;n; i++) &#123; for (int j = 0; j&lt;n; j++) printf(&quot;%4d&quot;, a[i][j]); printf(&quot;
