&quot; , tot); &#125; return 0;&#125; 小戴和他的烤肉 打表 禁忌的方法，打表 123456789101112131415161718192021222324#include &lt;stdio.h&gt;#define N 10005int get_prime(int n)&#123; if(n&lt;=1)return 0; for(int i=2;i*i&lt;=n;i++)&#123; if(n%i==0) return 1; &#125; return 0;&#125;bool get_ans(int x)&#123; while(x)&#123; if(!get_prime(x))return 0; x/=10; &#125; return 1;&#125;int main()&#123; for(int i=2;i&lt;=99999999;i++)&#123; if(get_ans(i))printf(&quot;%d,&quot;,i);// ,方便等会把结果直接存到数组 &#125; return 0;&#125; 之后存到数组里输出就好了。 DFS 想要得到要求的情况，首位肯定只能是2 3 5 7 因为个位的质数就这些 质数的结尾也不能是2或5的倍数 123456789101112131415161718192021222324252627282930313233#include &lt;cstdio&gt;int a[10] = &#123;0,1,3,7,9&#125;;int ans[10],n;//剪枝：质数的末尾只能是1,3,7,9bool get_prime(int n)&#123; if(n==1)return false; for(int i=2;i*i&lt;=n;i++)&#123; if(n%i==0) return false; &#125; return true;&#125;void print(int n) &#123; for(int i = 1; i &lt;= n; i ++) printf(&quot;%d&quot;,ans[i]); printf(&quot;
&quot;);&#125;//以ans记录数位上的数，满足条件则输出void dfs(int i,int sum) &#123;//i是当前第几个，sum是总和 if(get_prime(sum) == 0) return;//不是质数就返回 if(i == n + 1) print(n);//凑齐就输出 for(int j = 1; j &lt;= 4; j ++) &#123; ans[i] = a[j],dfs(i + 1,sum * 10 + a[j]),ans[i] = 0;//加上数位，搜下一层，回溯 &#125;&#125;int main() &#123; scanf(&quot;%d&quot;,&amp;n); ans[1] = 2,dfs(2,2);//第一位只能是2,3,5,7 ans[1] = 3,dfs(2,3); ans[1] = 5,dfs(2,5); ans[1] = 7,dfs(2,7); return 0;&#125;
